// ─── HELPERS ──────────────────────────────────────────────────────────────────
const totalPaid = s => s.payments.reduce((a,p) => a + p.amount, 0);
const balance   = s => s.totalPrice - totalPaid(s);
const isDMVReady = s => s.progress.preTrip >= 75 && s.progress.maneuvers >= 75 && s.progress.roadDriving >= 75;
const missingDocs = s => Object.entries(s.documents).filter(([,v]) => !v).map(([k]) => DOC_LABELS[k]);
const today = new Date().toISOString().split("T")[0];
const fmtDate = d => d ? new Date(d+"T12:00:00").toLocaleDateString("es-US",{month:"short",day:"numeric",year:"numeric"}) : "—";
const fmtCurrency = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n);
const addBizDays = (ds, days) => { const d=new Date(ds); let a=0; while(a<days){d.setDate(d.getDate()+1);const wd=d.getDay();if(wd!==0&&wd!==3&&wd!==6)a++;} return d.toISOString().split("T")[0]; };
const avgProgress = s => Math.round((s.progress.preTrip+s.progress.maneuvers+s.progress.roadDriving)/3);

