          <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid #f8fafc",fontSize:13}}><span style={{color:"#94a3b8"}}>{k}</span><span style={{fontWeight:700,color:v==="Passed"?"#15803d":v==="Failed"?"#b91c1c":"#0f172a"}}>{v}</span></div>
